import{c as t,Q as o,j as r,m as a}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"Useful Memories Become Faulty When Continuously Updated by LLMs","description":"","frontmatter":{"title":"Useful Memories Become Faulty When Continuously Updated by LLMs","author":"Hao Peng (@haopeng_uiuc) — Assistant Professor @ UIUC CS | PhD from UW | Formerly @allen_ai, @GoogleDeepMind, @Google","date":"2026-05-16T00:00:00.000Z","source":"https://x.com/haopeng_uiuc/status/2055695064148410764","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-16-@haopeng_uiuc-410764.md","filePath":"research/tweets/2026-05-16-@haopeng_uiuc-410764.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-05-16-@haopeng_uiuc-410764.md"};function i(n,e,l,d,h,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="useful-memories-become-faulty-when-continuously-updated-by-llms" tabindex="-1">Useful Memories Become Faulty When Continuously Updated by LLMs <a class="header-anchor" href="#useful-memories-become-faulty-when-continuously-updated-by-llms" aria-label="Permalink to &quot;Useful Memories Become Faulty When Continuously Updated by LLMs&quot;">​</a></h1><p><strong>注意</strong>：note tweet 格式，fxtwitter API 僅能取得 intro，全文請至原始連結閱讀</p><ul><li><strong>URL</strong>：<a href="https://x.com/haopeng_uiuc/status/2055695064148410764" target="_blank" rel="noreferrer">https://x.com/haopeng_uiuc/status/2055695064148410764</a></li><li><strong>作者</strong>：Hao Peng (@haopeng_uiuc) — Assistant Professor @ UIUC CS | PhD from UW | Formerly @allen_ai, @GoogleDeepMind, @Google</li><li><strong>日期</strong>：2026-05-16</li><li><strong>互動</strong>：237 likes · 23 RT · 191 bookmarks · 108,834 views</li><li><strong>論文</strong>：<a href="https://arxiv.org/pdf/2605.12978" target="_blank" rel="noreferrer">https://arxiv.org/pdf/2605.12978</a></li></ul><hr><h2 id="全文-note-tweet-intro" tabindex="-1">全文（Note Tweet Intro） <a class="header-anchor" href="#全文-note-tweet-intro" aria-label="Permalink to &quot;全文（Note Tweet Intro）&quot;">​</a></h2><p>Excited to share our new paper: &quot;Useful Memories Become Faulty When Continuously Updated by LLMs.&quot; Can LLM agents keep improving by turning past experience into compact, reusable memories?</p><p>We find this is much more fragile than it looks. Continuously consolidated memories can perform worse than no memory at all — sometimes even on problems the agent previously solved.</p><p>Episodic memories that preserve raw episodes are much more reliable.</p><p>There is still limited evidence that today&#39;s models can learn reusable abstractions from experience over the long term, which I believe is a crucial capability for agents that continuously improve.</p><p>Paper: <a href="https://arxiv.org/pdf/2605.12978" target="_blank" rel="noreferrer">https://arxiv.org/pdf/2605.12978</a>. Congrats to @dylan_works_ and team!</p><hr><h2 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to &quot;分析&quot;">​</a></h2><h3 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h3><p>LLM agent 持續壓縮記憶反而降質，原始情節記憶（episodic）遠比強制抽象化的整合記憶可靠。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>持續記憶整合比想象中脆弱</strong>：consolidate 後的 compact memory 可能比完全沒有記憶更差</li><li><strong>退化發生在已解決的問題上</strong>：即使 agent 曾經正確解過某問題，整合後也可能失效</li><li><strong>Episodic memory 更可靠</strong>：保留原始情節（raw episodes）的記憶策略表現優於抽象化總結</li><li><strong>模型學習長期可複用抽象的能力仍然有限</strong>：這被視為未來 agent 持續進步的關鍵缺口</li></ol><h3 id="關鍵數據-工具-引用" tabindex="-1">關鍵數據 / 工具 / 引用 <a class="header-anchor" href="#關鍵數據-工具-引用" aria-label="Permalink to &quot;關鍵數據 / 工具 / 引用&quot;">​</a></h3><ul><li>論文：arxiv.org/pdf/2605.12978</li><li>多環境（multiple environments）實驗驗證</li><li>引用 @dylan_works_（Dylan Zhang, UIUC CS PhD @ Google DeepMind）原始論文推文</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>受限於截斷</strong>：note tweet 格式，無法從 API 取得完整方法論與實驗細節，評分保守</li><li><strong>直接挑戰主流記憶架構</strong>：本 workspace 的 MEMORY.md + memory-compactor 模式正是「consolidation」範式，是否需要重新評估</li><li><strong>episodic vs consolidated 的平衡點尚未清楚</strong>：推文未說明多久整合一次才安全，需讀原始論文</li></ol><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>memory-compactor 直接相關；啟示保留原始 session 記錄優先於激進壓縮</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>反直覺發現：整合 = 退化，挑戰既有假設</td></tr><tr><td>C. 證據品質</td><td>6/10</td><td>多環境實驗存在，但 note tweet 截斷，細節需讀論文</td></tr><tr><td>D. 技術深度</td><td>6/10</td><td>高層次發現，具體技術在論文中；推文未提供實作細節</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>適用所有 LLM agent 記憶設計；不限 workspace 特定場景</td></tr></tbody></table><p><strong>加權總分</strong>：8×0.3 + 8×0.2 + 6×0.2 + 6×0.15 + 8×0.15 = <strong>7.3/10</strong></p><hr><h2 id="整合決策" tabindex="-1">整合決策 <a class="header-anchor" href="#整合決策" aria-label="Permalink to &quot;整合決策&quot;">​</a></h2><p><strong>Rule</strong> — 核心是通用原則：優先保留原始情節記憶，避免過度激進的記憶整合</p><p><strong>建議行動</strong>：</p><ul><li>閱讀完整論文 arxiv.org/pdf/2605.12978 確認實驗範圍</li><li>評估 memory-compactor 的整合頻率是否過於激進</li><li>考慮在 MEMORY.md 設計中加入 episodic 層（保留近期 N 個原始 session 記錄不整合）</li></ul>',29)])])}const m=t(s,[["render",i]]);export{c as __pageData,m as default};
